182	  void load_elf(const std::string& path)
183	  {
184	    const auto elf = LIEF::ELF::Parser::parse(path);
185	    if (!elf) {
186	      spdlog::critical("Check if it's a valid ELF file path : {}", path);
187	      exit(1);
188	    }
189	
190	    read_elf_into_memory(*elf, xlen_t{0}, platform.main_memory.data);
191	    for (auto& rv: platform.reset_vector)
192	      rv.write(elf->entrypoint());
