260	  int run(const uint64_t max_cycles = std::numeric_limits<uint64_t>::max())
261	  {
262	    auto sa = memzeroed<struct sigaction>();
263	    sa.sa_handler = sigint_handler;
264	    sigemptyset(&sa.sa_mask);
265	
266	    auto oact = memzeroed<struct sigaction>();
267	    if (sigaction(SIGINT, &sa, &oact) == -1)
268	      perror("sigaction");
269	
270	    const auto restore_sigint = std::experimental::scope_exit{[&] {
271	      if (sigaction(SIGINT, &oact, nullptr) == -1)
272	        perror("sigaction");
273	    }};
274	
275	    // wait for debugger connections
276	    while (dtm_debug && !dtm.is_connected()) {
277	      dtm.try_accept_socket();
278	      if (ctrlc != 0) {
279	        return 130;
280	      }
281	      sleep(1);
282	    }
283	
284	    [[maybe_unused]]
285	    bool ctx_resuming = context_config.continue_from;
286	    [[maybe_unused]]
287	    bool ctx_triggered = false;
288	
289	    for (auto n = uint64_t{0}; n < max_cycles; ++n) {
290	
291	      if (ctx_resuming) [[unlikely]] {
292	        // Pull up PLIC interrupt signal at the first cycle of the resume
293	        platform.int_trigger.write(1);
294	        ctx_resuming = false;
295	        ctx_triggered = true;
296	      }
297	
298	      sc_core::sc_start(platform.clk.period());
299	
300	      trace_.on_cycle(cpu);
301	
302	      if (trace_.pipeview_wants_exit()) {
303	        spdlog::info("Pipeline viewer requested exit (Kanata loop window complete)");
304	        return 0;
305	      }
306	
307	      if (context_config.save_on_wfi && platform.wfi_signal.read() == true)
308	        [[unlikely]]
309	      {
310	        context_config.save(platform, cpu);
311	        spdlog::info("User save context");
312	        return 0;
313	      }
314	
315	      if (ctrlc != 0) {
316	        ctrlc = 0;
317	        spdlog::info("Ctrl+C PC: {:x}", get_current_pc());
318	        trace_.log_committed_pcs(cpu);
319	        return 130;
320	      }
321	
322	      if (ctx_triggered) [[unlikely]] {
323	        // Pull down the interrupt signal after 1 cycle
324	        platform.int_trigger.write(0);
325	        ctx_triggered = false;
326	      }
327	
328	      if (platform.sim_control.exits >= 0) {
329	        spdlog::info("sim_control: got exit {}, stopping",
330	                     platform.sim_control.exits);
331	        spdlog::info("Exit PC: {:x}", get_current_pc());
332	        trace_.log_committed_pcs(cpu);
333	        return platform.sim_control.exits;
334	      }
335	
336	      if (this->cpu.contextp()->gotFinish())
337	        return 0;
338	
339	      spdlog::trace("PC: {:x}", get_current_pc());
340	    }
341	    return 0;
342	  }
343	
344	  uint64_t get_current_pc()
345	  {
346	    if constexpr (requires { cpu.get_current_pc(); }) {
347	      return cpu.get_current_pc();
348	    }
349	    return std::numeric_limits<uint64_t>::max();
350	  }
