397	  {
398	    namespace py = pybind11;
399	    auto c = py::class_<Simulator<CPU>>(m, name);
400	    c.def(py::init([](const char* name) { return new Simulator<CPU>(name); }));
401	    c.def("init_debug_port", &Simulator<CPU>::init_debug_port);
402	    c.def("load_elf", &Simulator<CPU>::load_elf);
403	    c.def("get_cycles", &Simulator<CPU>::get_cycles);
404	    c.def("reset", &Simulator<CPU>::reset);
405	    c.def("set_mem_latency", &Simulator<CPU>::set_mem_latency);
406	    c.def("get_exits", &Simulator<CPU>::get_exits);
407	    c.def("run", &Simulator<CPU>::run, "",
408	          py::arg("max_cycles") = std::numeric_limits<uint64_t>::max());
409	    c.def_readonly("cpu", &Simulator<CPU>::cpu,
410	                   py::return_value_policy::reference);
411	  }
412	#endif
