    "Copyright (C) 2013-2026 Andes Technology Corporation. All rights reserved.\n");
  fmt::print("Version : {}\n\n", ANDESCYCLE_VERSION);

  // output ACE, ACERVV support version
  if (get_libaceasim_version)
    fmt::print("Andes Custom Extension : {}\n", get_libaceasim_version());
}

static void print_help()
{
  print_version();
  fmt::print(R"(
Usage: sim_cpu_name [elf_file] [options]

AndesCycle CPU simulator for RISC-V processors

Argument:
  <elf_file>                  RISC-V ELF binary to simulate

General:
  --help, -h                  Print this help message and exit
  --version                   Display version information and exit
  --print-config              Show CPU configuration and exit
  --print-memmap              Show memory map layout and exit
  --log-level <level>         Set logging verbosity [default: 2]
                              (0=trace 1=debug 2=info 3=warn 4=error 5=critical 6=off)

Simulation:
  --mem-latency  <cycles>     Memory access latency in cycles [default: 1]
  --reset-vector <spec>       Set per-hart reset vector
                              <addr>        set all harts to <addr>
                              <hart>:<addr> set specific hart to <addr>
                              Overrides ELF entrypoint if specified

Tracing:
  --pc-trace  <file>          Enable PC trace logging to CSV file
  --kanata    <file>          Enable Kanata pipeline visualization logging
  --clarity   <file>          Enable Clarity pipeline visualization logging
  --objdump   <file>          Load objdump disassembly for pipeline viewer labels
  --kanata-loop-start <pc>    Start PC of the loop body (hex with 0x ok)
  --kanata-loop-end   <pc>    End PC of the loop body. Each retire of this PC
                              counts as one iteration; combine with --kanata or
                              --clarity to dump a steady-state window
  --kanata-loop-skip  <N>     Skip first N iterations [default: 0]
  --kanata-loop-record <X>    Record next X iterations then exit [default: 1]

Debug:
  --jtag-port <port>          JTAG remote bitbang port for OpenOCD [default: 9104]

Extra Options (require additional license):
  --ilm       <image>         Load ILM ROM image
  --dlm       <image>         Load DLM ROM image
  --waveform  <file>          Enable VCD/FST waveform tracing
  --save                      Save context when CPU enters WFI
  --continue                  Restore context and resume execution
  --context-dir <dir>         Context directory [default: ./saved_ctx]
)");
  // --ilm/--dlm: CPU-specific, not all CPUs have ILM/DLM
  // --waveform: requires compile flag VSIMDEBUG
  // --save/--continue/--context-dir: requires compile flag VSIMSAVABLE
}

extern "C" auto sc_main(const int argc, char* argv[]) -> int
try {
  spdlog::set_default_logger(spdlog::stderr_color_mt("stderr_logger"));
  spdlog::set_pattern("[%^%l%$] %v");

  const auto args = [&] {
    struct args
    {
      std::string pc_trace_file{};
      std::string elf_file{};
      std::optional<uint16_t> jtag_port = std::nullopt;
      bool memmap = false;
      std::string waveform_file{};
      unsigned mem_latency = 1;
      std::string ilm_file{};
      std::string dlm_file{};
      std::string kanata_file{};
      std::string objdump_file{};
      std::string clarity_file{};
      std::optional<uint64_t> kanata_loop_start{};
      std::optional<uint64_t> kanata_loop_end{};
      uint64_t kanata_loop_skip = 0;
      uint64_t kanata_loop_record = 1;
      std::vector<std::string> reset_vectors{};
      bool continue_ctx = false;
      bool save_ctx = false;
      std::string context_dir = "./saved_ctx/";
    } args;

    const auto help_and_exit = [] {
      print_help();
      exit(0);
    };

    auto p = parser{};
    p.shortflag('h', help_and_exit);
    p.longflag("help", help_and_exit);
    p.longflag("version", [] {
      print_version();
      exit(0);
    });
    p.longflag("print-memmap", [&] { args.memmap = true; });
    p.longflag("print-config", [] {
      print_cpu_configuration();
      exit(0);
    });
    p.longopt("jtag-port", [&](const std::string_view s) {
      if (auto n = to_int<uint16_t>(s); n)
        args.jtag_port = *n;
      else
        throw std::runtime_error("invalid number for --jtag-port: "
                                 + std::string{s});
    });
    p.longopt("mem-latency", [&](const std::string_view s) {
      if (auto n = to_int<unsigned>(s); n)
        args.mem_latency = *n;
      else
        throw std::runtime_error("invalid number for --mem-latency: "
                                 + std::string{s});
    });
    p.longopt("log-level", [](const std::string_view s) {
      if (auto n = to_int<uint16_t>(s); n) {
        *n = std::min(*n, (uint16_t) SPDLOG_LEVEL_OFF);
        spdlog::set_level(static_cast<spdlog::level::level_enum>(*n));
      } else {
        throw std::runtime_error("invalid number for --log-level: "
                                 + std::string{s});
      }
    });
    p.longopt("waveform",
              [&](const std::string_view s) { args.waveform_file = s; });
    p.longopt("ilm", [&](const std::string_view s) { args.ilm_file = s; });
    p.longopt("dlm", [&](const std::string_view s) { args.dlm_file = s; });
    p.longopt("pc-trace",
              [&](const std::string_view s) { args.pc_trace_file = s; });
    p.longopt("kanata",
              [&](const std::string_view s) { args.kanata_file = s; });
    p.longopt("objdump",
              [&](const std::string_view s) { args.objdump_file = s; });
    p.longopt("clarity",
              [&](const std::string_view s) { args.clarity_file = s; });
    p.longopt("kanata-loop-start", [&](const std::string_view s) {
      try {
        args.kanata_loop_start = std::stoull(std::string{s}, nullptr, 0);
      } catch (...) {
        throw std::runtime_error("invalid --kanata-loop-start: "
                                 + std::string{s});
      }
    });
    p.longopt("kanata-loop-end", [&](const std::string_view s) {
      try {
        args.kanata_loop_end = std::stoull(std::string{s}, nullptr, 0);
      } catch (...) {
        throw std::runtime_error("invalid --kanata-loop-end: "
                                 + std::string{s});
      }
    });
    p.longopt("kanata-loop-skip", [&](const std::string_view s) {
      try {
        args.kanata_loop_skip = std::stoull(std::string{s}, nullptr, 0);
      } catch (...) {
        throw std::runtime_error("invalid --kanata-loop-skip: "
                                 + std::string{s});
      }
    });
    p.longopt("kanata-loop-record", [&](const std::string_view s) {
      try {
        args.kanata_loop_record = std::stoull(std::string{s}, nullptr, 0);
      } catch (...) {
        throw std::runtime_error("invalid --kanata-loop-record: "
                                 + std::string{s});
      }
    });
    p.longflag("continue", [&] { args.continue_ctx = true; });
    p.longflag("save", [&] { args.save_ctx = true; });
    p.longopt("context-dir",
              [&](const std::string_view s) { args.context_dir = s; });
    p.longopt("reset-vector", [&](const std::string_view s) {
      args.reset_vectors.emplace_back(s);
    });
    p.posarg([&](const std::string_view s) { args.elf_file = s; });
    p.parse(std::vector<std::string_view>(argv, argv + argc));
    return args;
  }();

#ifndef VSIMSAVABLE
  if (args.save_ctx || args.continue_ctx || args.context_dir != "./saved_ctx/")
  {
    spdlog::critical(
      "--save, --continue, and --context-dir require VSIMSAVABLE build");
    std::exit(EXIT_FAILURE);
  }
#endif

  print_version();

  // systemc and cci init
  auto broker = cci_utils::broker{"global_broker"};
  cci::cci_register_broker(broker);

  const auto time_resolution = sc_core::sc_get_time_resolution();
  spdlog::debug("Using time resolution: {}", time_resolution.to_string());

  // run simulation
  const auto do_sim = [&]<typename CPU>() -> int {
    Simulator<CPU> sim{"sim"};

    if (args.memmap) {
      sim.platform.interconnect.dump_region();
      return 0;
    }

    sim.set_mem_latency(args.mem_latency);

    if (!args.ilm_file.empty())
      sim.load_image(args.ilm_file, MEM_TYPE::ILM);

    if (!args.dlm_file.empty())
      sim.load_image(args.dlm_file, MEM_TYPE::DLM);

    // End of elaboration
    sc_core::sc_start(sc_core::SC_ZERO_TIME);

    const auto t0 = std::chrono::steady_clock::now();

    if (!args.waveform_file.empty())
      sim.enable_waveform(args.waveform_file);

    if (!args.pc_trace_file.empty())
      sim.enable_pc_trace(args.pc_trace_file);

    if (!args.kanata_file.empty() && !args.clarity_file.empty())
      throw std::runtime_error("--kanata and --clarity are mutually exclusive");

    std::optional<kanata::LoopGate> loop_gate;
    if (args.kanata_loop_start.has_value()
        != args.kanata_loop_end.has_value())
      throw std::runtime_error(
        "--kanata-loop-start and --kanata-loop-end must be specified together");
    if (args.kanata_loop_start.has_value()) {
      if (args.kanata_file.empty() && args.clarity_file.empty())
        throw std::runtime_error(
          "--kanata-loop-* requires --kanata or --clarity");
      if (args.kanata_loop_record == 0)
        throw std::runtime_error("--kanata-loop-record must be >= 1");
      loop_gate = kanata::LoopGate{*args.kanata_loop_start,
                                   *args.kanata_loop_end,
                                   args.kanata_loop_skip,
                                   args.kanata_loop_record};
    }

    if (!args.kanata_file.empty())
      sim.enable_kanata(args.kanata_file, args.objdump_file, loop_gate);

    if (!args.clarity_file.empty())
      sim.enable_clarity(args.clarity_file, args.objdump_file, loop_gate);

    if (!args.elf_file.empty() && !args.continue_ctx)
      sim.load_elf(args.elf_file);

    // Apply per-hart reset vector overrides (after load_elf sets defaults)
    for (const auto& s: args.reset_vectors) {
      auto [hart, addr] = parse_reset_vector(s);
      if (hart) {
        sim.set_reset_vector(*hart, addr);
      } else {
        for (size_t i = 0; i < sim.platform.reset_vector.size(); ++i)
          sim.set_reset_vector(i, addr);
      }
    }

    if (args.continue_ctx)
      spdlog::info("You're resuming program from the given context");

    if (args.jtag_port)
      sim.init_debug_port(args.jtag_port.value());

    if (!args.jtag_port && args.elf_file.empty() && !args.continue_ctx)
      throw std::runtime_error("Required arg : program or --jtag-port");

    if (args.continue_ctx || args.save_ctx) {
      std::string_view s = args.context_dir;
      if (std::filesystem::exists(s) && !std::filesystem::is_directory(s))
        throw std::runtime_error("Error: Path " + std::string{s}
                                 + " exists but is not a directory.");
      if (!std::filesystem::exists(s)) {
        try {
          std::filesystem::create_directories(s);
        } catch (const std::filesystem::filesystem_error& e) {
          throw std::runtime_error(std::string{"Failed to create directory: "}
                                   + e.what());
        }
      }
      sim.context_config = {args.save_ctx, args.continue_ctx, args.context_dir};
    }

    sim.reset();

    const int exit_code = sim.run();

    sim.cpu.final();

    const auto t1 = std::chrono::steady_clock::now();
    const auto cycles = sim.get_cycles();
    spdlog::info("{} cycles simulated", cycles);
    if (cycles > 0) {
      const auto ms =
        std::chrono::duration_cast<std::chrono::milliseconds>(t1 - t0);
      spdlog::info("{}.{:03}s elapsed, {:.3f}Hz", ms.count() / 1000,
                   ms.count() % 1000,
                   double(cycles) / double(ms.count()) * 1000.0);
    }
    return exit_code;
  };

  return do_sim.operator()<VSIM_CPU_INTERFACE_CLASS>();

} catch (const std::exception& e) {
  spdlog::critical("fatal exception: {}\n", e.what());
  std::exit(EXIT_FAILURE);
} catch (...) {
  std::terminate();
}

