#pragma once

#include "pybind11.hpp"
#include "signals/internal_signals_ax45mpv.hpp"
#include "utils/ahb.hpp"
#include "utils/axi.hpp"
#include "utils/cpu_signal_registry.hpp"
#include "utils/duplicator.hpp"
#include "utils/ecc.hpp"
#include "utils/signals.hpp"

#include <axi/pin/axi4_initiator.h>
#include <axi/pin/axi4_target.h>
#include <spdlog/spdlog.h>
#include <systemc>
#include <Vax45mpv_premium.h>

#include <cstddef>

#include <array>

struct ax45mpv_premium_cpu_cluster_subsystem
    : public Vax45mpv_premium,
      public CpuSignalRegistry<ax45mpv_premium_cpu_cluster_subsystem>
{
  using SC_CURRENT_USER_MODULE = ax45mpv_premium_cpu_cluster_subsystem;

  ax45mpv_premium_cpu_cluster_subsystem(
    const sc_core::sc_module_name& name = "ax45mpv_premium")
      : Vax45mpv_premium{name}
  {}

#define VERILOG_DEFINE(key, value) static constexpr auto key = value;
#include <Vax45mpv_premium_config.h>

  // Limit maximum number of cores to 2 due to performance concerns
  static_assert(
    _NDS_NHART <= 2,
    "This subsystem only supports up to 2 cores. Please reconfigure with _NDS_NHART <= 2");

  static constexpr auto SYSTEM_BUS_TYPE = BusTypes::AXI;

  static constexpr auto dmi_addr_width = 9;
  static constexpr auto dmi_data_width = 32;
  static constexpr auto has_shared_cache = (NDS_L2C_CACHE_SIZE_KB > 0);

  using Vax45mpv_premium::contextp;
  using Vax45mpv_premium::final;
  using Vax45mpv_premium::modelName;
  using Vax45mpv_premium::threads;
  using Vax45mpv_premium::trace;

  using bus_cfg =
    axi::axi4_cfg<NDS_BIU_DATA_WIDTH, NDS_BIU_ADDR_WIDTH, NDS_BIU_ID_WIDTH, 1>;

  using slv_cfg = axi::
    axi4_cfg<NDS_BIU_DATA_WIDTH, NDS_BIU_ADDR_WIDTH, NDS_BIU_ID_WIDTH + 4, 1>;

  axi_signals<bus_cfg> mem{"mem"};
  axi::pin::axi4_target<bus_cfg> mem_bfm{"mem_bfm"};

  axi_signals<bus_cfg> mmio{"mmio"};
  axi::pin::axi4_target<bus_cfg> mmio_bfm{"mmio_bfm"};

#if _NDS_NHART > 1
  // signal adapters for multi-core
  BoolToUint<_NDS_NHART> mp_clk_dup{"mp_clk_dup"};
  sc_core::sc_signal<sc_dt::sc_uint<_NDS_NHART>> mp_core_clk;
#endif // _NDS_NHART

  UintToBool<_NDS_NHART> reset_narrow{"reset_narrow"};
  sc_core::sc_signal<bool> resetn_bool;

#ifdef _NDS_IO_HVM_SUBP
  axi_signals<slv_cfg> hvm{"hvm"};
  axi::pin::axi4_initiator<slv_cfg> hvm_bfm{"hvm_bfm"};
#endif // _NDS_IO_HVM_SUBP

#if _NDS_SLAVE_PORT_SUPPORT_INT == 1
  axi_signals<slv_cfg> slv{"slv"};
  axi::pin::axi4_initiator<slv_cfg> slv_bfm{"slv_bfm"};
#endif // _NDS_SLAVE_PORT_SUPPORT_INT

#if _NDS_IOCP_NUM > 0
  axi_signals<slv_cfg> iocp{"iocp"};
  axi::pin::axi4_initiator<slv_cfg> iocp_bfm{"iocp_bfm"};
#endif // _NDS_IOCP_NUM

#if _NDS_PC_GPR_PROBING_SUPPORT_INT == 1
  sc_core::sc_signal<vlpin<NDS_VALEN>> current_pc_hart0{"current_pc_hart0", 0};
  sc_core::sc_signal<vlpin<NDS_XLEN>> gpr_value_hart0{"gpr_value_hart0", 0};
  sc_core::sc_signal<vlpin<13>> gpr_index_hart0{"gpr_index_hart0", 0};

#if _NDS_NHART > 1
  sc_core::sc_signal<vlpin<NDS_VALEN>> current_pc_hart1{"current_pc_hart1", 0};
  sc_core::sc_signal<vlpin<NDS_XLEN>> gpr_value_hart1{"gpr_value_hart1", 0};
  sc_core::sc_signal<vlpin<13>> gpr_index_hart1{"gpr_index_hart1", 0};
#endif // _NDS_NHART

#endif // _NDS_PC_GPR_PROBING_SUPPORT_INT == 1

#if _NDS_NHART > 1
  sc_core::sc_signal<bool> wfi_signal_hart1;
#endif // _NDS_NHART

  void bind(
    const sc_core::sc_clock& clk,
    const sc_core::sc_signal<sc_dt::sc_uint<_NDS_NHART>>& reset,
    std::array<sc_core::sc_signal<vlpin<NDS_VALEN>>, _NDS_NHART>& reset_vector,
    ahb::signals<dmi_addr_width, dmi_data_width>& dmi,
    sc_core::sc_signal<bool>& wfi_signal,
    sc_core::sc_signal<sc_dt::sc_uint<31>>& int_trigger)
  {
    this->mem_bfm.clk_i.bind(clk);
    this->mmio_bfm.clk_i.bind(clk);

#define BIND_AXI(bfm, signals) \
  bfm.bind_ar(signals); \
  bfm.bind_r(signals); \
  bfm.bind_aw(signals); \
  bfm.bind_w(signals); \
  bfm.bind_b(signals);

    BIND_AXI(this->mem_bfm, this->mem);
    BIND_AXI(this->mmio_bfm, this->mmio);

#ifdef _NDS_IO_HVM_SUBP
    this->hvm_bfm.clk_i.bind(clk);
    BIND_AXI(this->hvm_bfm, this->hvm);
#endif // _NDS_IO_HVM_SUBP

#if _NDS_SLAVE_PORT_SUPPORT_INT == 1
    this->slv_bfm.clk_i.bind(clk);
    BIND_AXI(this->slv_bfm, this->slv);
#endif // _NDS_SLAVE_PORT_SUPPORT_INT

#if _NDS_IOCP_NUM > 0
    this->iocp_bfm.clk_i.bind(clk);
    BIND_AXI(this->iocp_bfm, this->iocp);
#endif // _NDS_IOCP_NUM

#undef BIND_AXI

#ifdef _NDS_IO_HVM_SUBP
#define X(ch, name) this->hvm_sub_##ch##name.bind(this->hvm.ch##_##name);
    EXPAND_AXI4_SIGNALS
#undef X
#endif // _NDS_IO_HVM_SUBP

#if _NDS_SLAVE_PORT_SUPPORT_INT == 1
#define X(ch, name) this->slv_##ch##name.bind(this->slv.ch##_##name);
    EXPAND_AXI4_SIGNALS
#undef X
#endif // _NDS_SLAVE_PORT_SUPPORT_INT

#if _NDS_IOCP_NUM > 0
#define X(ch, name) this->iocp0_##ch##name.bind(this->iocp.ch##_##name);
    EXPAND_AXI4_SIGNALS
#undef X
#endif // _NDS_IOCP_NUM

#define X(ch, name) \
  this->mem_##ch##name.bind(this->mem.ch##_##name); \
  this->mmio_##ch##name.bind(this->mmio.ch##_##name);
    EXPAND_AXI4_SIGNALS
#undef X

#define X(name) this->dmi_##name.bind(dmi.name);
    EXPAND_AHB_SIGNALS_NO_HREADY
#undef X
    this->dmi_hreadyout.bind(dmi.hready);

    this->dmi_hsel.bind(signals::one);
    this->dmi_hready.bind(signals::one);

#if _NDS_NHART > 1
    mp_clk_dup.sig_in.bind(clk);
    mp_clk_dup.sig_out.bind(mp_core_clk);

    this->core_clk.bind(mp_core_clk);
    this->dc_clk.bind(mp_core_clk);
    this->lm_clk.bind(mp_core_clk);
    this->vpu_clk.bind(mp_core_clk);
    this->vpu_vace_clk.bind(mp_core_clk);
    this->vpu_valu_clk.bind(mp_core_clk);
    this->vpu_vdiv_clk.bind(mp_core_clk);
    this->vpu_vfdiv_clk.bind(mp_core_clk);
    this->vpu_vfmis_clk.bind(mp_core_clk);
    this->vpu_vlsu_clk.bind(mp_core_clk);
    this->vpu_vmac_clk.bind(mp_core_clk);
    this->vpu_vmask_clk.bind(mp_core_clk);
    this->vpu_vpermut_clk.bind(mp_core_clk);
    this->vpu_vsp_clk.bind(mp_core_clk);
    this->core_resetn.bind(reset);
    this->slvp_resetn.bind(reset);
    this->core_l2_resetn.bind(reset);
#else // _NDS_NHART == 1
    this->core_clk.bind(clk);
    this->dc_clk.bind(clk);
    this->lm_clk.bind(clk);
